@keyframes tail-wag {
  0%, 100% { transform: rotate(0deg); }
  25% { transform: rotate(12deg); }
  75% { transform: rotate(-8deg); }
}

/* === MAGICAL PARTICLES === */
@keyframes particle-float {
  0%, 100% { transform: translateY(0) translateX(0); opacity: 0.6; }
  25% { transform: translateY(-20px) translateX(10px); opacity: 1; }
  50% { transform: translateY(-40px) translateX(-5px); opacity: 0.8; }
  75% { transform: translateY(-60px) translateX(15px); opacity: 0.4; }
}

@keyframes particle-pulse {
  0%, 100% { transform: scale(0.8); opacity: 0.4; }
  50% { transform: scale(1.4); opacity: 1; }
}

@keyframes firefly-drift {
  0% { transform: translate(0, 0); opacity: 0; }
  20% { opacity: 0.8; }
  80% { opacity: 0.8; }
  100% { transform: translate(var(--drift-x, 60px), var(--drift-y, -80px)); opacity: 0; }
}

/* === BREATHING / EAR WIGGLE === */
@keyframes pet-breathe {
  0%, 100% { transform: scaleY(1) scaleX(1); }
  50% { transform: scaleY(1.03) scaleX(0.98); }
}

@keyframes ear-wiggle-left {
  0%, 100% { transform: rotate(0deg); }
  10% { transform: rotate(-8deg); }
  20% { transform: rotate(4deg); }
  30% { transform: rotate(-4deg); }
  40% { transform: rotate(0deg); }
}

@keyframes ear-wiggle-right {
  0%, 100% { transform: rotate(0deg); }
  10% { transform: rotate(8deg); }
  20% { transform: rotate(-4deg); }
  30% { transform: rotate(4deg); }
  40% { transform: rotate(0deg); }
}

/* === SPARKLE / ENERGY BAR === */
@keyframes sparkle-burst {
  0% { transform: scale(0) rotate(0deg); opacity: 1; }
  100% { transform: scale(1.5) rotate(180deg); opacity: 0; }
}

@keyframes energy-sparkle {
  0% { transform: translateX(0) scale(0); opacity: 1; }
  50% { transform: translateX(20px) scale(1); opacity: 0.8; }
  100% { transform: translateX(40px) scale(0); opacity: 0; }
}

/* === GLOW / SHIMMER === */
@keyframes glow-pulse {
  0%, 100% { box-shadow: 0 0 20px rgba(74,124,89,0.2), 0 0 40px rgba(74,124,89,0.1); }
  50% { box-shadow: 0 0 30px rgba(74,124,89,0.4), 0 0 60px rgba(74,124,89,0.2); }
}

@keyframes inner-glow-sweep {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

/* === CONFETTI FALL === */
@keyframes confetti-fall {
  0% { transform: translateY(-20px) rotate(0deg); opacity: 1; }
  100% { transform: translateY(100vh) rotate(720deg); opacity: 0; }
}

/* === TOAST BOUNCE === */
@keyframes toast-bounce-in {
  0% { transform: translateY(-100px) scale(0.8); opacity: 0; }
  60% { transform: translateY(10px) scale(1.05); opacity: 1; }
  80% { transform: translateY(-5px) scale(0.98); }
  100% { transform: translateY(0) scale(1); }
}

/* === FLOAT ISLAND === */
@keyframes island-float {
  0%, 100% { transform: translateY(0) rotate(0deg); }
  25% { transform: translateY(-6px) rotate(0.5deg); }
  75% { transform: translateY(-4px) rotate(-0.3deg); }
}

/* === CLASSES === */
.particle {
  position: absolute;
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(255,255,255,0.9) 0%, rgba(233,196,106,0.6) 100%);
  animation: particle-float var(--duration, 4s) ease-in-out infinite;
  animation-delay: var(--delay, 0s);
  pointer-events: none;
  filter: blur(0.5px);
}

.particle-glow {
  position: absolute;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(231,111,81,0.8) 0%, transparent 70%);
  animation: particle-pulse var(--duration, 3s) ease-in-out infinite;
  animation-delay: var(--delay, 0s);
  pointer-events: none;
}

.firefly {
  position: absolute;
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: #e9c46a;
  box-shadow: 0 0 6px 2px rgba(233,196,106,0.6);
  animation: firefly-drift var(--duration, 6s) ease-in-out infinite;
  animation-delay: var(--delay, 0s);
  pointer-events: none;
}

.spatial-card {
  position: relative;
  background: rgba(255, 255, 255, 0.65);
  backdrop-filter: blur(20px) saturate(140%);
  -webkit-backdrop-filter: blur(20px) saturate(140%);
  border: 1px solid rgba(255, 255, 255, 0.5);
  border-radius: 20px;
  overflow: hidden;
}

.spatial-card::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 1px;
  background: linear-gradient(
    135deg,
    rgba(255, 255, 255, 0.5) 0%,
    rgba(255, 255, 255, 0.1) 30%,
    rgba(255, 255, 255, 0) 50%,
    rgba(255, 255, 255, 0.1) 70%,
    rgba(255, 255, 255, 0.4) 100%
  );
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
  mix-blend-mode: overlay;
}

.spatial-card::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 40%;
  background: linear-gradient(180deg, rgba(255,255,255,0.25) 0%, transparent 100%);
  border-radius: 20px 20px 0 0;
  pointer-events: none;
}

.glow-shadow {
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.08),
    0 0 60px rgba(74, 124, 89, 0.12),
    0 0 120px rgba(74, 124, 89, 0.06),
    inset 0 1px 0 rgba(255, 255, 255, 0.5);
}

.glow-coral {
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.08),
    0 0 60px rgba(231, 111, 81, 0.15),
    0 0 120px rgba(231, 111, 81, 0.08),
    inset 0 1px 0 rgba(255, 255, 255, 0.5);
}

.spring-touch {
  transition: transform 0.15s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.spring-touch:active {
  transform: scale(0.95);
}

.confetti-piece {
  position: absolute;
  width: 10px;
  height: 10px;
  animation: confetti-fall var(--duration, 3s) ease-out forwards;
  animation-delay: var(--delay, 0s);
}

.toast-bounce {
  animation: toast-bounce-in 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.island-bob {
  animation: island-float 4s ease-in-out infinite;
}

.pet-breathe {
  animation: pet-breathe 3s ease-in-out infinite;
}

.ear-left {
  animation: ear-wiggle-left 4s ease-in-out infinite;
  animation-delay: 1s;
}

.ear-right {
  animation: ear-wiggle-right 4s ease-in-out infinite;
  animation-delay: 2.5s;
}

.energy-spark {
  position: absolute;
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: #f4a261;
  box-shadow: 0 0 4px 2px rgba(244, 162, 97, 0.6);
  animation: energy-sparkle 0.6s ease-out forwards;
  pointer-events: none;
}

