export default function MagicalParticles() {
  const particles = Array.from({ length: 12 }, (_, i) => ({
    id: i,
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100}%`,
    delay: `${Math.random() * 4}s`,
    duration: `${3 + Math.random() * 3}s`,
    size: 2 + Math.random() * 4,
    isFirefly: i % 3 === 0,
  }));

  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none" style={{ zIndex: 1 }}>
      {particles.map((p) =>
        p.isFirefly ? (
          <div
            key={p.id}
            className="firefly"
            style={{
              left: p.left,
              top: p.top,
              animationDelay: p.delay,
              animationDuration: p.duration,
              ['--drift-x' as string]: `${(Math.random() - 0.5) * 120}px`,
              ['--drift-y' as string]: `${-40 - Math.random() * 80}px`,
            }}
          />
        ) : (
          <div
            key={p.id}
            className="particle-glow"
            style={{
              left: p.left,
              top: p.top,
              width: p.size,
              height: p.size,
              animationDelay: p.delay,
              animationDuration: p.duration,
            }}
          />
        )
      )}
    </div>
  );
}

import { useEffect, useState } from "react";

const COLORS = ["#e76f51", "#f4a261", "#e9c46a", "#2a9d8f", "#4a7c59", "#e8b4b8", "#f8e8d8"];

interface ConfettiPiece {
  id: number;
  left: number;
  color: string;
  delay: number;
  duration: number;
  size: number;
  rotation: number;
  shape: "circle" | "square" | "triangle";
}

export default function Confetti({ trigger }: { trigger: boolean }) {
  const [pieces, setPieces] = useState<ConfettiPiece[]>([]);

  useEffect(() => {
    if (trigger) {
      const newPieces: ConfettiPiece[] = Array.from({ length: 40 }, (_, i) => ({
        id: i,
        left: 10 + Math.random() * 80,
        color: COLORS[Math.floor(Math.random() * COLORS.length)],
        delay: Math.random() * 0.5,
        duration: 2 + Math.random() * 2,
        size: 6 + Math.random() * 10,
        rotation: Math.random() * 360,
        shape: ["circle", "square", "triangle"][Math.floor(Math.random() * 3)] as any,
      }));
      setPieces(newPieces);
      const timer = setTimeout(() => setPieces([]), 5000);
      return () => clearTimeout(timer);
    }
  }, [trigger]);

  if (pieces.length === 0) return null;

  return (
    <div className="fixed inset-0 pointer-events-none overflow-hidden" style={{ zIndex: 9999 }}>
      {pieces.map((p) => (
        <div
          key={p.id}
          className="confetti-piece"
          style={{
            left: `${p.left}%`,
            top: "-10px",
            backgroundColor: p.color,
            width: p.size,
            height: p.shape === "triangle" ? p.size * 0.8 : p.size,
            borderRadius: p.shape === "circle" ? "50%" : p.shape === "square" ? "2px" : "0",
            clipPath: p.shape === "triangle" ? "polygon(50% 0%, 0% 100%, 100% 100%)" : "none",
            transform: `rotate(${p.rotation}deg)`,
            ["--duration" as string]: `${p.duration}s`,
            ["--delay" as string]: `${p.delay}s`,
          }}
        />
      ))}
    </div>
  );
}

import { motion } from "framer-motion";
import { ReactNode } from "react";

interface SpatialCardProps {
  children: ReactNode;
  className?: string;
  glow?: "sage" | "coral" | "none";
  onClick?: () => void;
  delay?: number;
}

export default function SpatialCard({ children, className = "", glow = "sage", onClick, delay = 0 }: SpatialCardProps) {
  const glowClass = glow === "sage" ? "glow-shadow" : glow === "coral" ? "glow-coral" : "";

  return (
    <motion.div
      initial={{ opacity: 0, y: 20, scale: 0.96 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{
        delay,
        type: "spring",
        stiffness: 300,
        damping: 25,
        mass: 0.8,
      }}
      whileHover={{
        scale: 1.02,
        y: -3,
        transition: { type: "spring", stiffness: 400, damping: 20 },
      }}
      whileTap={{
        scale: 0.96,
        transition: { type: "spring", stiffness: 500, damping: 15 },
      }}
      onClick={onClick}
      className={`spatial-card ${glowClass} ${onClick ? "cursor-pointer" : ""} ${className}`}
    >
      {children}
    </motion.div>
