                  initial={{ width: "0%" }}
                  animate={{ width: `${energy}%` }}
                  transition={{ duration: 1.2, type: "spring", stiffness: 60 }}
                />
                <AnimatePresence>
                  {sparks.map((s) => (
                    <div key={s.id} className="energy-spark" style={{ left: `${s.x}%`, top: 0 }} />
                  ))}
                </AnimatePresence>
              </div>
              <p className="text-[11px] text-[#7B6658] mt-2">
