/* === PREMIUM GLASS CARD === */
.premium-glass-card {
  background: rgba(255, 255, 255, 0.55);
  backdrop-filter: blur(24px) saturate(150%);
  -webkit-backdrop-filter: blur(24px) saturate(150%);
  border: 1px solid rgba(255, 255, 255, 0.5);
  border-radius: 24px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.06), inset 0 1px 0 rgba(255, 255, 255, 0.4);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.premium-glass-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 0 40px rgba(243, 211, 122, 0.08), inset 0 1px 0 rgba(255, 255, 255, 0.5);
}

/* Grain overlay */
.grain-overlay {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 999;
  opacity: 0.03;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  background-repeat: repeat;
  background-size: 128px 128px;
}

/* Pet animations */
.pet-breathe {
  animation: breathe 3s ease-in-out infinite;
}

@keyframes breathe {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.03); }
}

.ear-left {
  animation: earLeft 2s ease-in-out infinite;
  transform-origin: 32px 14px;
}

@keyframes earLeft {
  0%, 100% { transform: rotate(0deg); }
  50% { transform: rotate(-12deg); }
}

.ear-right {
  animation: earRight 2s ease-in-out infinite;
  transform-origin: 88px 14px;
}

@keyframes earRight {
  0%, 100% { transform: rotate(0deg); }
  50% { transform: rotate(12deg); }
}

.pet-tail {
  animation: tailWag 2s ease-in-out infinite;
  transform-origin: 92px 75px;
}

@keyframes tailWag {
  0%, 100% { transform: rotate(0deg); }
  50% { transform: rotate(8deg); }
}

/* Energy spark */
.energy-spark {
  position: absolute;
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: #F3D37A;
  animation: sparkle 0.6s ease-out forwards;
}

@keyframes sparkle {
  0% { transform: scale(1); opacity: 1; }
  100% { transform: scale(0); opacity: 0; }
}

