   124→                      ? "0 0 20px rgba(74,124,89,0.4), 0 4px 12px rgba(74,124,89,0.3)"
   125→                      : m.status === "Đợi"
   126→                      ? "none"
   127→                      : "0 4px 12px rgba(243,211,122,0.3)",
   128→                    opacity: m.status === "Đợi" ? 0.5 : 1,
   129→                  }}
   130→                >
   131→                  <span className="text-[14px] font-bold text-white">{m.name[0]}</span>
   132→                  {m.status === "Đợi" && (
   133→                    <div className="absolute -bottom-1 -right-1">
   134→                      <motion.div
   135→                        animate={{ opacity: [0.3, 1, 0.3] }}
   136→                        transition={{ duration: 1.5, repeat: Infinity }}
   137→                      >
   138→                        <Clock className="w-4 h-4 text-[#7B6658]" />
   139→                      </motion.div>
   140→                    </div>
   141→                  )}
   142→                </motion.div>
