}

/* === DARK HERO CARD === */
.dark-hero-card {
  background: linear-gradient(135deg, #0F2D25, #143B31);
  border: 1px solid rgba(98, 201, 165, 0.15);
  border-radius: 28px;
  box-shadow: 0 16px 48px rgba(7, 31, 26, 0.3), 0 0 60px rgba(98, 201, 165, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.1);
  color: white;
  overflow: hidden;
  position: relative;
}

.dark-hero-card::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -50%;
  width: 100%;
  height: 100%;
  background: radial-gradient(circle, rgba(244, 208, 111, 0.08) 0%, transparent 60%);
  pointer-events: none;
}

/* === PET ROOM / STAGE === */
.pet-room {
  background: linear-gradient(180deg, #0F2D25 0%, #071F1A 50%, #0F2D25 100%);
  border: 1px solid rgba(98, 201, 165, 0.2);
  border-radius: 32px;
  box-shadow: 0 20px 60px rgba(7, 31, 26, 0.35), 0 0 80px rgba(98, 201, 165, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.08);
  position: relative;
  overflow: hidden;
}

.pet-room::after {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 60%;
  height: 40%;
  background: radial-gradient(ellipse, rgba(244, 208, 111, 0.12) 0%, transparent 70%);
  pointer-events: none;
}

.pet-orb {
  position: relative;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.25) 0%, rgba(255, 255, 255, 0.05) 50%, transparent 70%),
              radial-gradient(circle at 70% 70%, rgba(98, 201, 165, 0.15) 0%, transparent 50%);
  box-shadow: inset 0 0 30px rgba(255, 255, 255, 0.15), 0 0 40px rgba(244, 208, 111, 0.15);
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.pet-platform {
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  width: 140px;
  height: 20px;
  background: radial-gradient(ellipse, rgba(0, 0, 0, 0.15) 0%, transparent 70%);
  border-radius: 50%;
  filter: blur(8px);
}

