@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — OBSIDIAN GLASS + ELECTRIC MINT
   2026 Tech Unicorn Dark Mode: Sharp, Expensive, Minimal
   ============================================================ */

/* === GLOBAL RESETS === */
html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #09090B;
  color: #FAFAFA;
}

/* === CSS VARIABLES: DARK DESIGN TOKENS === */
:root {
  /* Core dark palette */
  --obsidian: #09090B;
  --surface: #121214;
  --surface-elevated: #18181B;
  --surface-hover: #1E1E22;
  --border-subtle: rgba(255, 255, 255, 0.08);
  --border-medium: rgba(255, 255, 255, 0.12);
  --text-primary: #FAFAFA;
  --text-secondary: #A1A1AA;
  --text-muted: #71717A;
  --text-dim: #52525B;

  /* Electric Mint accent */
  --mint: #00E5A8;
  --mint-hover: #34F5C5;
  --mint-dim: rgba(0, 229, 168, 0.15);
  --mint-glow: rgba(0, 229, 168, 0.25);

  /* Functional colors */
  --warning: #F5C542;
  --danger: #FF4D6D;
  --danger-dim: rgba(255, 77, 109, 0.15);

  /* shadcn overrides */
  --background: 240 6% 4%;
  --foreground: 0 0% 98%;
  --muted: 240 4% 10%;
  --muted-foreground: 240 5% 65%;
  --popover: 240 6% 6%;
  --popover-foreground: 0 0% 98%;
  --border: 240 4% 16%;
  --input: 240 4% 16%;
  --card: 240 6% 6%;
  --card-foreground: 0 0% 98%;
  --primary: 162 100% 45%;
  --primary-foreground: 240 6% 4%;
  --secondary: 240 4% 12%;
  --secondary-foreground: 0 0% 98%;
  --accent: 162 100% 45%;
  --accent-foreground: 240 6% 4%;
  --destructive: 350 100% 65%;
  --destructive-foreground: 0 0% 98%;
  --ring: 162 100% 45%;
  --radius: 0.75rem;

  /* Shadows */
  --shadow-dark: 0 12px 40px rgba(0, 0, 0, 0.35);
  --shadow-card: 0 4px 24px rgba(0, 0, 0, 0.2);
  --shadow-dock: 0 -4px 24px rgba(0, 0, 0, 0.3);
  --shadow-inner-highlight: inset 0 1px 1px rgba(255, 255, 255, 0.35);
  --shadow-neutral: 0 4px 16px rgba(0, 0, 0, 0.15);

  /* Animation */
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

/* === LAYER: BASE === */
@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground;
    background: var(--obsidian);
    color: var(--text-primary);
  }

  /* Focus Ring */
  button:focus-visible,
  a:focus-visible {
    outline: none;
    ring: 2px;
    ring-color: var(--mint);
    ring-offset: 2px;
    ring-offset-color: var(--obsidian);
  }
}

/* === LAYER: COMPONENTS === */
@layer components {

  /* === OBSIDIAN SHELL === */
  .obsidian-shell {
    background: var(--obsidian);
    min-height: 100vh;
    position: relative;
    overflow-x: hidden;
  }

  /* === OBSIDIAN CARD === */
  .obsidian-card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    backdrop-filter: blur(24px);
    -webkit-backdrop-filter: blur(24px);
    transition: border-color 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }

  .obsidian-card:hover {
    border-color: var(--border-medium);
  }

  /* === OBSIDIAN CARD ELEVATED === */
  .obsidian-card-elevated {
    background: var(--surface-elevated);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    box-shadow: var(--shadow-card);
  }

  /* === AMBIENT MINT BLUR === */
  .ambient-mint-blur {
    position: absolute;
    width: 300px;
    height: 300px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(0, 229, 168, 0.08) 0%, transparent 70%);
    filter: blur(80px);
    pointer-events: none;
    z-index: 0;
  }

  /* === PREMIUM BOTTOM DOCK === */
  .premium-bottom-dock {
    position: fixed;
    bottom: 12px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 50;
    background: rgba(18, 18, 20, 0.72);
    backdrop-filter: blur(24px) saturate(140%);
    -webkit-backdrop-filter: blur(24px) saturate(140%);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 20px;
    box-shadow: var(--shadow-dock);
  }

  /* === PREMIUM VOTE BUTTON === */
  .premium-vote-button {
    background: var(--surface-elevated);
    border: 1px solid var(--border-subtle);
    border-radius: 14px;
    padding: 16px 12px;
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-vote-button:hover {
    border-color: var(--border-medium);
    transform: translateY(-2px);
  }

  .premium-vote-button:active {
    transform: scale(0.97);
  }

  .premium-vote-button.selected {
    background: var(--mint-dim);
    border-color: var(--mint);
  }

  .premium-vote-button.danger {
    background: var(--danger-dim);
    border-color: rgba(255, 77, 109, 0.3);
  }

  .premium-vote-button.danger.selected {
    background: rgba(255, 77, 109, 0.25);
    border-color: var(--danger);
  }

  /* === PREMIUM CTA === */
  .premium-cta {
    background: #FAFAFA;
    color: #09090B;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: var(--shadow-inner-highlight), var(--shadow-dark);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta:hover {
    background: #FFFFFF;
    transform: translateY(-1px);
    box-shadow: var(--shadow-inner-highlight), 0 16px 48px rgba(0, 0, 0, 0.4);
  }

  .premium-cta:active {
    transform: scale(0.98);
  }

  /* === CTA ALT (MINT) === */
  .premium-cta-mint {
    background: var(--mint);
    color: #03110D;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: var(--shadow-inner-highlight), 0 12px 40px rgba(0, 0, 0, 0.35);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta-mint:hover {
    background: var(--mint-hover);
    transform: translateY(-1px);
  }

  .premium-cta-mint:active {
    transform: scale(0.98);
  }

  /* === AVATAR TOKEN === */
  .avatar-token {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 14px;
    position: relative;
  }

  .avatar-token.active {
    background: var(--surface-elevated);
    border: 2px solid var(--mint);
    color: var(--text-primary);
  }

  .avatar-token.pending {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    color: var(--text-muted);
    opacity: 0.6;
  }

  .avatar-token.maybe {
    background: var(--surface-elevated);
    border: 1px solid var(--border-medium);
    color: var(--text-secondary);
  }

  /* Status dot */
  .avatar-token .status-dot {
    position: absolute;
    bottom: -2px;
    right: -2px;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--mint);
    border: 2px solid var(--obsidian);
  }

  .avatar-token .status-dot.warning {
    background: var(--warning);
  }

  /* === PROGRESS BAR === */
  .progress-track {
    width: 100%;
    height: 6px;
    background: var(--surface-elevated);
    border-radius: 3px;
    overflow: hidden;
  }

  .progress-fill {
    height: 100%;
    background: var(--mint);
    border-radius: 3px;
    transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  /* === STATUS PILL === */
  .status-pill {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 4px 10px;
    border-radius: 100px;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.02em;
  }

  .status-pill.mint {
    background: var(--mint-dim);
    color: var(--mint);
    border: 1px solid rgba(0, 229, 168, 0.2);
  }

  .status-pill.warning {
    background: rgba(245, 197, 66, 0.12);
    color: var(--warning);
    border: 1px solid rgba(245, 197, 66, 0.2);
  }

  .status-pill.muted {
    background: var(--surface-elevated);
    color: var(--text-muted);
    border: 1px solid var(--border-subtle);
  }

  /* === PAGE LABEL === */
  .page-label {
    font-size: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.22em;
    color: var(--text-muted);
  }

  /* === BENTO GRID === */
  .bento {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
  }

  .bento-3 {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
  }

  .bento-asymmetric {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 12px;
  }

  /* === GRAIN OVERLAY === */
  .grain-overlay {
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 999;
    opacity: 0.02;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat;
    background-size: 128px 128px;
  }
}

/* === LAYER: UTILITIES === */
@layer utilities {
  .text-shadow-glow {
    text-shadow: 0 0 20px rgba(0, 229, 168, 0.3);
  }
}

/* === KEYFRAMES === */
@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes pulse-ring {
  0% { transform: scale(0.8); opacity: 1; }
  100% { transform: scale(1.5); opacity: 0; }
}

@keyframes fade-in {
  0% { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: none; }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

@keyframes spin {
  to { transform: rotate(1turn); }
}

