            animate={{ width: `${progress}%` }}
            transition={{ duration: 0.8, ease: [0.34, 1.56, 0.64, 1] }}
          />
        </div>
      </motion.div>

      {/* Members Card */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
