                      ? "rgba(0, 229, 168, 0.12)"
                      : choice.variant === "danger"
                      ? "rgba(255, 77, 109, 0.12)"
                      : "rgba(255, 255, 255, 0.06)"
                    : "#18181B",
                  borderColor: isSelected
                    ? choice.variant === "mint"
