                      : choice.variant === "danger"
                      ? "rgba(255, 77, 109, 0.5)"
                      : "rgba(255,255,255,0.15)"
                    : "rgba(255,255,255,0.08)",
                }}
              >
                <Icon
                  className="w-5 h-5"
                  style={{
                    color: isSelected
                      ? choice.variant === "mint"
                        ? "#00E5A8"
                        : choice.variant === "danger"
                        ? "#FF4D6D"
                        : "#FAFAFA"
                      : choice.variant === "mint"
                      ? "#00E5A8"
                      : choice.variant === "danger"
                      ? "#FF4D6D"
                      : "#71717A",
                  }}
                />
                <span
                  className="text-[13px] font-semibold"
