    const newEnergy = Math.min(100, energy + 15);
    setEnergy(newEnergy);
    setIsHappy(true);
    const newSparks = Array.from({ length: 8 }, (_, i) => ({
      id: sparkId + i,
      x: energy + (newEnergy - energy) * (i / 8),
    }));
