@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — ARCTIC CHROME
   2026 Tech Unicorn: Navy Deep + Ice Blue
   Inspired by Figma, Codeium, Linear dark mode
   ============================================================ */

/* === GLOBAL RESETS === */
html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #0A0F1E;
  color: #F0F4FF;
}

/* === CSS VARIABLES: ARCTIC CHROME TOKENS === */
:root {
  /* Core navy palette */
  --bg: #0A0F1E;
  --surface: #0E1526;
  --surface-elevated: #131D30;
  --surface-hover: #1A2540;
  --border-subtle: rgba(96, 165, 250, 0.10);
  --border-medium: rgba(96, 165, 250, 0.18);

  /* Text hierarchy */
  --text-primary: #F0F4FF;
  --text-secondary: #94A3B8;
  --text-muted: #64748B;
  --text-dim: #475569;

  /* Ice blue accent — single source of truth */
  --blue: #60A5FA;
  --blue-bright: #93C5FD;
  --blue-dim: rgba(96, 165, 250, 0.12);
  --blue-glow: rgba(96, 165, 250, 0.20);

  /* Functional colors */
  --warning: #FBBF24;
  --danger: #F87171;
  --danger-dim: rgba(248, 113, 113, 0.14);

  /* shadcn overrides */
  --background: 222 47% 9%;
  --foreground: 213 100% 97%;
  --muted: 222 30% 12%;
  --muted-foreground: 215 20% 60%;
  --popover: 222 47% 10%;
  --popover-foreground: 213 100% 97%;
  --border: 217 32% 18%;
  --input: 217 32% 18%;
  --card: 222 47% 10%;
  --card-foreground: 213 100% 97%;
  --primary: 213 94% 68%;
  --primary-foreground: 222 47% 9%;
  --secondary: 222 30% 14%;
  --secondary-foreground: 213 100% 97%;
  --accent: 213 94% 68%;
  --accent-foreground: 222 47% 9%;
  --destructive: 0 72% 71%;
  --destructive-foreground: 213 100% 97%;
  --ring: 213 94% 68%;
  --radius: 0.75rem;

  /* Shadows */
  --shadow-dark: 0 12px 40px rgba(0, 0, 0, 0.45);
  --shadow-card: 0 4px 24px rgba(0, 0, 0, 0.30);
  --shadow-dock: 0 -4px 32px rgba(0, 0, 0, 0.40);
  --shadow-inner-highlight: inset 0 1px 1px rgba(255, 255, 255, 0.30);
  --shadow-blue-glow: 0 8px 32px rgba(96, 165, 250, 0.15);

  /* Animation easing */
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

/* === LAYER: BASE === */
@layer base {
  * {
    @apply border-border;
  }
  body {
    background: var(--bg);
    color: var(--text-primary);
  }
}

/* === LAYER: COMPONENTS === */
@layer components {

  /* === OBSIDIAN CARD (now: Arctic Card) === */
  .obsidian-card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    transition: border-color 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }

  .obsidian-card:hover {
    border-color: var(--border-medium);
  }

  /* Elevated card */
  .obsidian-card-elevated {
    background: var(--surface-elevated);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    box-shadow: var(--shadow-card);
  }

  /* === AMBIENT BLUE BLUR === */
  .ambient-mint-blur {
    position: absolute;
    width: 320px;
    height: 320px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(96, 165, 250, 0.07) 0%, transparent 70%);
    filter: blur(80px);
    pointer-events: none;
    z-index: 0;
  }

  /* === PREMIUM BOTTOM DOCK — FIXED === */
  .premium-bottom-dock {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 50;
    background: rgba(10, 15, 30, 0.85);
    backdrop-filter: blur(24px) saturate(140%);
    -webkit-backdrop-filter: blur(24px) saturate(140%);
    border-top: 1px solid rgba(96, 165, 250, 0.10);
    box-shadow: var(--shadow-dock);
  }

  /* === VOTE BUTTONS === */
  .premium-vote-button {
    background: var(--surface-elevated);
    border: 1px solid var(--border-subtle);
    border-radius: 14px;
    padding: 16px 12px;
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-vote-button:hover {
    border-color: var(--border-medium);
    transform: translateY(-2px);
  }

  .premium-vote-button:active {
    transform: scale(0.97);
  }

  .premium-vote-button.selected {
    background: var(--blue-dim);
    border-color: var(--blue);
  }

  .premium-vote-button.danger {
    background: var(--danger-dim);
    border-color: rgba(248, 113, 113, 0.25);
  }

  .premium-vote-button.danger.selected {
    background: rgba(248, 113, 113, 0.18);
    border-color: var(--danger);
  }

  /* === PRIMARY CTA — White button === */
  .premium-cta {
    background: #FFFFFF;
    color: #0A0F1E;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: var(--shadow-inner-highlight), var(--shadow-dark);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta:hover {
    background: #F0F4FF;
    transform: translateY(-1px);
    box-shadow: var(--shadow-inner-highlight), 0 16px 48px rgba(0, 0, 0, 0.5);
  }

  .premium-cta:active {
    transform: scale(0.98);
  }

  /* === CTA BLUE (secondary) === */
  .premium-cta-mint {
    background: var(--blue);
    color: #0A0F1E;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: var(--shadow-inner-highlight), var(--shadow-blue-glow);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta-mint:hover {
    background: var(--blue-bright);
    transform: translateY(-1px);
  }

  .premium-cta-mint:active {
    transform: scale(0.98);
  }

  /* === AVATAR TOKEN === */
  .avatar-token {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 14px;
    position: relative;
  }

  .avatar-token.active {
    background: var(--surface-elevated);
    border: 2px solid var(--blue);
    color: var(--text-primary);
  }

  .avatar-token.pending {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    color: var(--text-muted);
    opacity: 0.5;
  }

  .avatar-token.maybe {
    background: var(--surface-elevated);
    border: 1px solid var(--border-medium);
    color: var(--text-secondary);
  }

  /* Status dot */
  .avatar-token .status-dot {
    position: absolute;
    bottom: -2px;
    right: -2px;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--blue);
    border: 2px solid var(--bg);
  }

  .avatar-token .status-dot.warning {
    background: var(--warning);
  }

  /* === PROGRESS BAR === */
  .progress-track {
    width: 100%;
    height: 5px;
    background: var(--surface-hover);
    border-radius: 3px;
    overflow: hidden;
  }

  .progress-fill {
    height: 100%;
    background: var(--blue);
    border-radius: 3px;
    transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  /* === STATUS PILL === */
  .status-pill {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 3px 9px;
    border-radius: 100px;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.02em;
  }

  .status-pill.mint {
    background: var(--blue-dim);
    color: var(--blue-bright);
    border: 1px solid rgba(96, 165, 250, 0.20);
  }

  .status-pill.warning {
    background: rgba(251, 191, 36, 0.12);
    color: var(--warning);
    border: 1px solid rgba(251, 191, 36, 0.20);
  }

  .status-pill.muted {
    background: var(--surface-elevated);
    color: var(--text-muted);
    border: 1px solid var(--border-subtle);
  }

  /* === PAGE LABEL === */
  .page-label {
    font-size: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.22em;
    color: var(--text-muted);
  }

  /* === BENTO GRID === */
  .bento {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
  }

  .bento-3 {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
  }

  .bento-asymmetric {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 12px;
  }

  /* === GRAIN OVERLAY === */
  .grain-overlay {
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 999;
    opacity: 0.018;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat;
    background-size: 128px 128px;
  }
}

/* === KEYFRAMES === */
@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

import { useLocation } from "wouter";
import { Home, Calendar, Heart, PawPrint } from "lucide-react";
import { motion } from "framer-motion";

/* ============================================================
   BOTTOM NAV — Arctic Chrome Glass Dock
   Full-width bar pinned to bottom, never floating/cut-off
   ============================================================ */

const tabs = [
  { path: "/home", label: "Trang chủ", icon: Home },
  { path: "/plan", label: "Plan", icon: Calendar },
  { path: "/vote", label: "Vote", icon: VoteIcon },
  { path: "/memories", label: "Kỷ niệm", icon: Heart },
  { path: "/pet", label: "Pet", icon: PawPrint },
];

function VoteIcon({ className }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="18" height="18" rx="2" />
      <path d="M9 12l2 2 4-4" />
    </svg>
  );
}

export default function BottomNav() {
  const [location, setLocation] = useLocation();

  return (
    <motion.nav
      initial={{ y: 80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ type: "spring", stiffness: 400, damping: 35, delay: 0.15 }}
      className="fixed bottom-0 left-0 right-0 z-50"
      style={{
        background: "rgba(10, 15, 30, 0.88)",
        backdropFilter: "blur(28px) saturate(160%)",
        WebkitBackdropFilter: "blur(28px) saturate(160%)",
        borderTop: "1px solid rgba(96, 165, 250, 0.10)",
        boxShadow: "0 -4px 32px rgba(0,0,0,0.35)",
        paddingBottom: "env(safe-area-inset-bottom, 0px)",
      }}
    >
      <div className="flex items-stretch justify-around max-w-md mx-auto px-2">
        {tabs.map((tab) => {
          const isActive = location === tab.path;
          const Icon = tab.icon;
          return (
            <motion.button
              key={tab.path}
              onClick={() => setLocation(tab.path)}
              whileTap={{ scale: 0.86 }}
              className="flex flex-col items-center justify-center gap-0.5 flex-1 py-3 relative focus:outline-none"
              data-testid={`nav-${tab.path.slice(1)}`}
            >
              {/* Active top indicator */}
              {isActive && (
                <motion.div
                  layoutId="nav-indicator"
                  className="absolute top-0 left-1/2 -translate-x-1/2 h-[2px] w-6 rounded-full"
                  style={{ background: "#60A5FA" }}
                  transition={{ type: "spring", stiffness: 500, damping: 30 }}
                />
              )}

              <motion.div
                animate={isActive ? { scale: 1.1 } : { scale: 1 }}
                transition={{ type: "spring", stiffness: 400, damping: 20 }}
                style={{ color: isActive ? "#60A5FA" : "#475569" }}
              >
                <Icon className="w-[22px] h-[22px]" />
              </motion.div>

              <motion.span
                animate={isActive ? { opacity: 1 } : { opacity: 0.45 }}
                className="text-[9.5px] font-semibold tracking-wide leading-none"
                style={{ color: isActive ? "#60A5FA" : "#475569" }}
              >
                {tab.label}
              </motion.span>
            </motion.button>
          );
        })}
      </div>
    </motion.nav>
  );
}

import { Switch, Route } from "wouter";
