            <div className="text-[11px] font-semibold px-2.5 py-1 rounded-full"
              style={{ background: "rgba(96,165,250,0.10)", color: BLUE_BRIGHT, border: `1px solid rgba(96,165,250,0.20)` }}>Level {level}</div>
          </div>
          <div className="grid grid-cols-3 gap-2">
            {[
              { icon: <Heart className="w-4 h-4" />, label: "Nhãn dán", locked: false, unlockAt: 1 },
              { icon: <Star className="w-4 h-4" />, label: "Mũ len", locked: false, unlockAt: 2 },
              { icon: <Trophy className="w-4 h-4" />, label: "Huy hiệu", locked: true, unlockAt: 5 },
              { icon: <Crown className="w-4 h-4" />, label: "Vương miện", locked: true, unlockAt: 8 },
              { icon: <Zap className="w-4 h-4" />, label: "Aura xanh", locked: true, unlockAt: 10 },
              { icon: <Sparkles className="w-4 h-4" />, label: "Star dust", locked: true, unlockAt: 12 },
            ].map((r, i) => (
              <motion.div key={r.label}
                initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }}
                transition={{ delay: 0.55 + i * 0.05, type: "spring", stiffness: 400, damping: 20 }}
                whileHover={!r.locked ? { scale: 1.08, y: -4 } : {}}
                className="relative flex flex-col items-center rounded-2xl p-2.5 border"
                style={{ background: r.locked ? SURF2 : "rgba(96,165,250,0.08)", borderColor: r.locked ? BORDER : "rgba(96,165,250,0.20)", opacity: r.locked ? 0.55 : 1 }}>
                <motion.div animate={!r.locked ? { rotate: [0, 6, -6, 0] } : {}} transition={{ duration: 2, repeat: Infinity, repeatDelay: 3 }}
                  className="mb-1" style={{ color: r.locked ? T3 : BLUE }}>
                  {r.icon}
                </motion.div>
                <span className="text-[10px] font-semibold text-center leading-tight" style={{ color: T1 }}>{r.label}</span>
                {r.locked && <>
                  <Lock className="absolute top-1.5 right-1.5 w-2.5 h-2.5" style={{ color: T3 }} />
                  <span className="text-[8px] mt-0.5" style={{ color: T3 }}>Lv {r.unlockAt}</span>
                </>}
              </motion.div>
            ))}
          </div>
        </div>
      </motion.div>

      {/* Achievements */}
      <motion.div custom={9} variants={cardVariants} initial="hidden" animate="visible" className="mb-5">
        <div className="rounded-2xl p-4" style={{ background: SURF, border: `1px solid ${BORDER}` }}>
          <div className="text-[10px] font-semibold uppercase tracking-[0.22em] mb-3" style={{ color: T3 }}>Thành tích gần đây</div>
          <div className="flex gap-2">
            {[
              { icon: Trophy, label: "First Gather", desc: "Tạo plan đầu", active: true },
              { icon: Heart, label: "Social Star", desc: "Vote 5 lần", active: true },
              { icon: Camera, label: "Photographer", desc: "12 ảnh", active: false },
            ].map((b, i) => (
              <motion.div key={b.label} initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }}
                transition={{ delay: 0.65 + i * 0.1, type: "spring" }} whileHover={{ scale: 1.05, y: -2 }}
                className="flex-1 flex flex-col items-center rounded-2xl p-2.5 border"
                style={{ background: b.active ? "rgba(96,165,250,0.08)" : SURF2, borderColor: b.active ? "rgba(96,165,250,0.20)" : BORDER, opacity: b.active ? 1 : 0.5 }}>
                <b.icon className="w-4 h-4 mb-1" style={{ color: b.active ? BLUE : T3 }} />
                <span className="text-[10px] font-semibold text-center leading-tight" style={{ color: T1 }}>{b.label}</span>
                <span className="text-[8px]" style={{ color: T3 }}>{b.desc}</span>
              </motion.div>
            ))}
          </div>
        </div>
      </motion.div>

      <BottomNav />
    </div>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — FRESH LIGHT MODE
   Clean, airy, vibrant — inspired by Linear, Craft, Notion
   ============================================================ */

html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #F1F5FB;
  color: #0F172A;
}

/* === CSS VARIABLES === */
:root {
  --bg: #F1F5FB;
  --surface: #FFFFFF;
  --surface-elevated: #F0F5FF;
  --surface-hover: #E8F0FE;
  --border-subtle: rgba(0, 0, 0, 0.07);
  --border-medium: rgba(0, 0, 0, 0.13);

  --text-primary: #0F172A;
  --text-secondary: #475569;
  --text-muted: #94A3B8;
  --text-dim: #CBD5E1;

  --blue: #3B82F6;
  --blue-bright: #2563EB;
  --blue-dim: rgba(59, 130, 246, 0.10);
  --blue-glow: rgba(59, 130, 246, 0.18);

  --warning: #F59E0B;
  --danger: #EF4444;
  --danger-dim: rgba(239, 68, 68, 0.10);

  /* shadcn overrides */
  --background: 213 33% 95%;
  --foreground: 222 47% 7%;
  --muted: 213 20% 93%;
  --muted-foreground: 215 16% 47%;
  --popover: 0 0% 100%;
  --popover-foreground: 222 47% 7%;
  --border: 213 20% 89%;
  --input: 213 20% 89%;
  --card: 0 0% 100%;
  --card-foreground: 222 47% 7%;
  --primary: 217 91% 60%;
  --primary-foreground: 0 0% 100%;
  --secondary: 213 20% 93%;
  --secondary-foreground: 222 47% 7%;
  --accent: 217 91% 60%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;
  --ring: 217 91% 60%;
  --radius: 0.75rem;

  --shadow-card: 0 1px 3px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.06);
  --shadow-card-hover: 0 4px 8px rgba(0,0,0,0.08), 0 12px 32px rgba(0,0,0,0.09);
  --shadow-dock: 0 -1px 0 rgba(0,0,0,0.06), 0 -8px 24px rgba(0,0,0,0.05);
  --shadow-inner-highlight: inset 0 1px 1px rgba(255,255,255,0.40);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@layer base {
  * { @apply border-border; }
  body { background: var(--bg); color: var(--text-primary); }
}

@layer components {

  .obsidian-card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    box-shadow: var(--shadow-card);
    transition: box-shadow 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }

  .obsidian-card:hover {
    box-shadow: var(--shadow-card-hover);
  }

  .obsidian-card-elevated {
    background: var(--surface-elevated);
    border: 1px solid var(--border-subtle);
    border-radius: 16px;
    box-shadow: var(--shadow-card);
  }

  .ambient-mint-blur {
    position: absolute;
    width: 320px;
    height: 320px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(59,130,246,0.06) 0%, transparent 70%);
    filter: blur(80px);
    pointer-events: none;
    z-index: 0;
  }

  /* Bottom dock */
  .premium-bottom-dock {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 50;
    background: rgba(255,255,255,0.90);
    backdrop-filter: blur(24px) saturate(180%);
    -webkit-backdrop-filter: blur(24px) saturate(180%);
    border-top: 1px solid rgba(0,0,0,0.07);
    box-shadow: var(--shadow-dock);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  /* Primary CTA — dark button */
  .premium-cta {
    background: #0F172A;
    color: #FFFFFF;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: 0 2px 8px rgba(15,23,42,0.25);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta:hover {
    background: #1E293B;
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(15,23,42,0.30);
  }

  .premium-cta:active { transform: scale(0.98); }

  /* Blue CTA */
  .premium-cta-mint {
    background: var(--blue);
    color: #FFFFFF;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: 0 2px 8px rgba(59,130,246,0.30);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }

  .premium-cta-mint:hover {
    background: var(--blue-bright);
    transform: translateY(-1px);
    box-shadow: 0 4px 20px rgba(59,130,246,0.38);
  }

  .premium-cta-mint:active { transform: scale(0.98); }

  .avatar-token {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 14px;
    position: relative;
  }

  .avatar-token.active {
    background: var(--blue-dim);
    border: 2px solid var(--blue);
    color: var(--blue-bright);
  }

  .avatar-token.pending {
    background: #F8FAFC;
    border: 1px solid var(--border-subtle);
    color: var(--text-muted);
    opacity: 0.6;
  }

  .avatar-token.maybe {
    background: rgba(245,158,11,0.10);
    border: 1px solid rgba(245,158,11,0.25);
    color: #B45309;
  }

  .avatar-token .status-dot {
    position: absolute;
    bottom: -2px;
    right: -2px;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: #22C55E;
    border: 2px solid white;
  }

  .avatar-token .status-dot.warning {
    background: var(--warning);
  }

  .progress-track {
    width: 100%;
    height: 6px;
    background: #E2E8F0;
    border-radius: 3px;
    overflow: hidden;
  }

  .progress-fill {
    height: 100%;
    background: var(--blue);
    border-radius: 3px;
    transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  .status-pill {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 3px 9px;
    border-radius: 100px;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.02em;
  }

  .status-pill.mint {
    background: rgba(59,130,246,0.10);
    color: #2563EB;
    border: 1px solid rgba(59,130,246,0.20);
  }

  .status-pill.warning {
    background: rgba(245,158,11,0.10);
    color: #92400E;
    border: 1px solid rgba(245,158,11,0.22);
  }

  .status-pill.muted {
    background: #F1F5F9;
    color: var(--text-muted);
    border: 1px solid var(--border-subtle);
  }

  .page-label {
    font-size: 10px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.22em;
    color: var(--text-muted);
  }

  .bento {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
  }

  .bento-3 {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
  }

  .bento-asymmetric {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 12px;
  }

  .grain-overlay {
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 999;
    opacity: 0.012;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat;
    background-size: 128px 128px;
  }
}

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

import { useLocation } from "wouter";
import { Home, Calendar, Heart, PawPrint } from "lucide-react";
import { motion } from "framer-motion";

const tabs = [
  { path: "/home", label: "Trang chủ", icon: Home },
  { path: "/plan", label: "Plan", icon: Calendar },
  { path: "/vote", label: "Vote", icon: VoteIcon },
  { path: "/memories", label: "Kỷ niệm", icon: Heart },
  { path: "/pet", label: "Pet", icon: PawPrint },
];

function VoteIcon({ className }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="18" height="18" rx="2" />
      <path d="M9 12l2 2 4-4" />
    </svg>
  );
}

export default function BottomNav() {
  const [location, setLocation] = useLocation();

  return (
    <motion.nav
      initial={{ y: 80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ type: "spring", stiffness: 400, damping: 35, delay: 0.15 }}
      className="fixed bottom-0 left-0 right-0 z-50"
      style={{
        background: "rgba(255,255,255,0.92)",
        backdropFilter: "blur(28px) saturate(180%)",
        WebkitBackdropFilter: "blur(28px) saturate(180%)",
        borderTop: "1px solid rgba(0,0,0,0.07)",
        boxShadow: "0 -1px 0 rgba(0,0,0,0.05), 0 -8px 24px rgba(0,0,0,0.04)",
        paddingBottom: "env(safe-area-inset-bottom, 0px)",
      }}
    >
      <div className="flex items-stretch justify-around max-w-md mx-auto px-2">
        {tabs.map((tab) => {
          const isActive = location === tab.path;
          const Icon = tab.icon;
          return (
            <motion.button
              key={tab.path}
              onClick={() => setLocation(tab.path)}
              whileTap={{ scale: 0.86 }}
              className="flex flex-col items-center justify-center gap-0.5 flex-1 py-3 relative focus:outline-none"
              data-testid={`nav-${tab.path.slice(1)}`}
            >
              {isActive && (
                <motion.div
                  layoutId="nav-indicator"
                  className="absolute top-0 left-1/2 -translate-x-1/2 h-[2px] w-6 rounded-full"
                  style={{ background: "#3B82F6" }}
                  transition={{ type: "spring", stiffness: 500, damping: 30 }}
                />
              )}
              <motion.div
                animate={isActive ? { scale: 1.1 } : { scale: 1 }}
                transition={{ type: "spring", stiffness: 400, damping: 20 }}
                style={{ color: isActive ? "#3B82F6" : "#94A3B8" }}
              >
                <Icon className="w-[22px] h-[22px]" />
              </motion.div>
              <motion.span
                animate={isActive ? { opacity: 1 } : { opacity: 0.5 }}
                className="text-[9.5px] font-semibold tracking-wide leading-none"
                style={{ color: isActive ? "#3B82F6" : "#94A3B8" }}
              >
                {tab.label}
              </motion.span>
            </motion.button>
          );
        })}
      </div>
    </motion.nav>
  );
}

