  );
  if (frameId === "nature") return (
    <div style={{ width: s, height: s, position: "relative", overflow: "hidden", borderRadius: 8 }}>
      <img src={photoUrl} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
