@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — UNICORN EDITION
   Warm ivory palette. Depth. Emotion. Artistry.
   ============================================================ */

html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #F7F5F0;
  color: #0F172A;
}

:root {
  --bg: #F7F5F0;
  --bg-warm: #F2EEE7;
  --surface: #FFFFFF;
  --surface-warm: #FEFCF8;
  --surface-elevated: #F5F0E8;
  --surface-hover: #EDE8DF;
  --border-subtle: rgba(0, 0, 0, 0.07);
  --border-medium: rgba(0, 0, 0, 0.13);

  --text-primary: #0F172A;
  --text-secondary: #475569;
  --text-muted: #94A3B8;
  --text-dim: #CBD5E1;

  --blue: #3B82F6;
  --blue-bright: #2563EB;
  --blue-dim: rgba(59, 130, 246, 0.10);
  --blue-glow: rgba(59, 130, 246, 0.22);

  --amber: #F59E0B;
  --amber-dim: rgba(245, 158, 11, 0.10);
  --green: #22C55E;
  --coral: #F97316;
  --coral-dim: rgba(249, 115, 22, 0.10);

  --warning: #F59E0B;
  --danger: #EF4444;
  --danger-dim: rgba(239, 68, 68, 0.10);

  /* shadcn */
  --background: 37 25% 96%;
  --foreground: 222 47% 7%;
  --muted: 37 15% 92%;
  --muted-foreground: 215 16% 47%;
  --popover: 0 0% 100%;
  --popover-foreground: 222 47% 7%;
  --border: 37 15% 88%;
  --input: 37 15% 88%;
  --card: 0 0% 100%;
  --card-foreground: 222 47% 7%;
  --primary: 217 91% 60%;
  --primary-foreground: 0 0% 100%;
  --secondary: 37 15% 92%;
  --secondary-foreground: 222 47% 7%;
  --accent: 217 91% 60%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;
  --ring: 217 91% 60%;
  --radius: 0.75rem;

  --shadow-sm: 0 1px 2px rgba(0,0,0,0.05);
  --shadow-card: 0 1px 3px rgba(0,0,0,0.05), 0 4px 16px rgba(0,0,0,0.05);
  --shadow-card-hover: 0 4px 8px rgba(0,0,0,0.07), 0 12px 32px rgba(0,0,0,0.09);
  --shadow-float: 0 8px 32px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.06);
  --shadow-dock: 0 -1px 0 rgba(0,0,0,0.06), 0 -8px 24px rgba(0,0,0,0.05);
  --shadow-inner-highlight: inset 0 1px 1px rgba(255,255,255,0.40);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@layer base {
  * { @apply border-border; }
  body { background: var(--bg); color: var(--text-primary); }
}

@layer components {

  .card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 18px;
    box-shadow: var(--shadow-card);
    transition: box-shadow 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }
  .card:hover { box-shadow: var(--shadow-card-hover); }

  .card-warm {
    background: var(--surface-warm);
    border: 1px solid rgba(0,0,0,0.06);
    border-radius: 18px;
    box-shadow: var(--shadow-card);
  }

  .card-float {
    background: var(--surface);
    border: 1px solid rgba(255,255,255,0.60);
    border-radius: 20px;
    box-shadow: var(--shadow-float);
  }

  /* Legacy compat */
  .obsidian-card { @apply card; }
  .obsidian-card-elevated { @apply card-warm; }

  .ambient-mint-blur {
    position: absolute;
    width: 320px;
    height: 320px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(59,130,246,0.07) 0%, transparent 70%);
    filter: blur(80px);
    pointer-events: none;
    z-index: 0;
  }

  .ambient-amber-blur {
    position: absolute;
    width: 260px;
    height: 260px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(245,158,11,0.07) 0%, transparent 70%);
    filter: blur(70px);
    pointer-events: none;
    z-index: 0;
  }

  /* Bottom dock */
  .premium-bottom-dock {
    position: fixed;
    bottom: 0; left: 0; right: 0;
    z-index: 50;
    background: rgba(255,255,255,0.92);
    backdrop-filter: blur(28px) saturate(180%);
    -webkit-backdrop-filter: blur(28px) saturate(180%);
    border-top: 1px solid rgba(0,0,0,0.07);
    box-shadow: var(--shadow-dock);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  /* Primary CTA — dark */
  .premium-cta {
    background: #0F172A;
    color: #FFFFFF;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: 0 2px 8px rgba(15,23,42,0.25);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }
  .premium-cta:hover { background: #1E293B; transform: translateY(-1px); box-shadow: 0 4px 16px rgba(15,23,42,0.30); }
  .premium-cta:active { transform: scale(0.98); }

  /* Blue CTA */
  .premium-cta-mint {
    background: var(--blue);
    color: #FFFFFF;
    border: none;
    border-radius: 14px;
    font-weight: 700;
    font-size: 16px;
    box-shadow: 0 2px 12px rgba(59,130,246,0.35);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }
  .premium-cta-mint:hover { background: var(--blue-bright); transform: translateY(-1px); box-shadow: 0 4px 20px rgba(59,130,246,0.42); }
  .premium-cta-mint:active { transform: scale(0.98); }

  /* Ghost CTA for dark backgrounds */
  .premium-cta-ghost {
    background: rgba(255,255,255,0.12);
    color: rgba(255,255,255,0.90);
    border: 1px solid rgba(255,255,255,0.20);
    border-radius: 14px;
    font-weight: 600;
    font-size: 15px;
    backdrop-filter: blur(12px);
    transition: all 0.2s var(--ease-smooth);
    cursor: pointer;
  }
  .premium-cta-ghost:hover { background: rgba(255,255,255,0.20); }
  .premium-cta-ghost:active { transform: scale(0.98); }

  .avatar-token {
    width: 56px; height: 56px;
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-weight: 700; font-size: 14px;
    position: relative;
  }
  .avatar-token.active {
    background: var(--blue-dim);
    border: 2px solid var(--blue);
    color: var(--blue-bright);
  }
  .avatar-token.pending {
    background: #F8FAFC;
    border: 1px solid var(--border-subtle);
    color: var(--text-muted);
    opacity: 0.6;
  }
  .avatar-token.maybe {
    background: rgba(245,158,11,0.10);
    border: 1px solid rgba(245,158,11,0.25);
    color: #B45309;
  }
  .avatar-token .status-dot {
    position: absolute; bottom: -2px; right: -2px;
    width: 14px; height: 14px;
    border-radius: 50%;
    background: #22C55E;
    border: 2px solid white;
  }
  .avatar-token .status-dot.warning { background: var(--warning); }

  .progress-track {
    width: 100%; height: 6px;
    background: #E2E8F0;
    border-radius: 3px; overflow: hidden;
  }
  .progress-fill {
    height: 100%;
    background: var(--blue);
    border-radius: 3px;
    transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  .status-pill {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 3px 9px;
    border-radius: 100px;
    font-size: 11px; font-weight: 600;
    letter-spacing: 0.02em;
  }
  .status-pill.mint { background: rgba(59,130,246,0.10); color: #2563EB; border: 1px solid rgba(59,130,246,0.20); }
  .status-pill.warning { background: rgba(245,158,11,0.10); color: #92400E; border: 1px solid rgba(245,158,11,0.22); }
  .status-pill.muted { background: #F1F5F9; color: var(--text-muted); border: 1px solid var(--border-subtle); }
  .status-pill.green { background: rgba(34,197,94,0.10); color: #15803D; border: 1px solid rgba(34,197,94,0.22); }

  .page-label {
    font-size: 10px; font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.22em;
    color: var(--text-muted);
  }

  .bento { display: grid; grid-template-columns: repeat(2, 1fr); gap: 12px; }
  .bento-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; }
  .bento-asymmetric { display: grid; grid-template-columns: 2fr 1fr; gap: 12px; }

  /* Best match glow card */
  .match-glow-card {
    border: 2px solid rgba(59,130,246,0.40) !important;
    box-shadow: 0 0 0 4px rgba(59,130,246,0.08), 0 8px 32px rgba(59,130,246,0.18) !important;
  }

  /* Urgency banner */
  .urgency-banner {
    background: linear-gradient(135deg, #0F172A 0%, #1E3A8A 100%);
    border-radius: 16px;
    box-shadow: 0 4px 20px rgba(15,23,42,0.20);
  }

  /* AI hint chip */
  .ai-hint {
    background: linear-gradient(135deg, rgba(59,130,246,0.08), rgba(139,92,246,0.08));
    border: 1px solid rgba(59,130,246,0.16);
    border-radius: 12px;
    padding: 10px 14px;
  }

  .grain-overlay {
    position: fixed; inset: 0;
    pointer-events: none; z-index: 999;
    opacity: 0.015;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat; background-size: 128px 128px;
  }
}

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

@keyframes confetti-fall {
  0%   { transform: translateY(-10px) rotate(var(--rot, 0deg)) scale(1); opacity: 1; }
  80%  { opacity: 1; }
  100% { transform: translateY(110vh) rotate(calc(var(--rot, 0deg) + 540deg)) scale(0.6); opacity: 0; }
}

.confetti-piece {
  position: absolute;
  animation: confetti-fall var(--duration, 3s) var(--delay, 0s) ease-in forwards;
}

@keyframes glow-pulse {
  0%, 100% { opacity: 0.35; transform: scale(1); }
  50% { opacity: 0.65; transform: scale(1.15); }
}

@keyframes glow-ring-expand {
  0% { opacity: 0.5; transform: scale(0.95); }
  100% { opacity: 0; transform: scale(1.5); }
}

@keyframes slide-up-fade {
  0% { opacity: 0; transform: translateY(12px); }
  100% { opacity: 1; transform: translateY(0); }
}

@keyframes activity-in {
  0% { opacity: 0; transform: translateY(-8px) scale(0.96); }
  100% { opacity: 1; transform: translateY(0) scale(1); }
}

import { Switch, Route } from "wouter";
import { AnimatePresence, motion } from "framer-motion";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import NotFound from "@/pages/not-found";

import Onboarding from "@/pages/Onboarding";
import Home from "@/pages/Home";
import Plan from "@/pages/Plan";
import CreatePlan from "@/pages/CreatePlan";
import Suggested from "@/pages/Suggested";
import PlanDetail from "@/pages/PlanDetail";
import Vote from "@/pages/Vote";
import Confirmed from "@/pages/Confirmed";
import Memories from "@/pages/Memories";
import Photobooth from "@/pages/Photobooth";
import Pet from "@/pages/Pet";

function AppShell({ children }: { children: React.ReactNode }) {
  return (
    <div className="min-h-screen flex flex-col max-w-md mx-auto relative overflow-x-hidden" style={{ background: "#F7F5F0" }}>
      <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">
        <div className="absolute top-[-80px] right-[-60px] w-[320px] h-[320px] rounded-full"
          style={{ background: "radial-gradient(circle, rgba(59,130,246,0.06) 0%, transparent 70%)", filter: "blur(60px)" }} />
        <div className="absolute bottom-[20%] left-[-40px] w-[240px] h-[240px] rounded-full"
          style={{ background: "radial-gradient(circle, rgba(245,158,11,0.05) 0%, transparent 70%)", filter: "blur(50px)" }} />
      </div>
      <div className="grain-overlay" />
      <div className="relative z-10 flex-1 flex flex-col">
        {children}
      </div>
    </div>
  );
}

const pageTransition = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0 },
  exit: { opacity: 0, y: -8 },
  transition: { type: "spring" as const, stiffness: 400, damping: 34 },
};

function PageWrapper({ children }: { children: React.ReactNode }) {
  return (
    <motion.div
      initial={pageTransition.initial}
      animate={pageTransition.animate}
      exit={pageTransition.exit}
      transition={pageTransition.transition}
      className="flex-1 flex flex-col"
    >
      {children}
    </motion.div>
  );
}

function Router() {
  return (
    <Switch>
      <Route path="/"><PageWrapper><Onboarding /></PageWrapper></Route>
      <Route path="/home"><PageWrapper><Home /></PageWrapper></Route>
      <Route path="/plan"><PageWrapper><Plan /></PageWrapper></Route>
      <Route path="/create-plan"><PageWrapper><CreatePlan /></PageWrapper></Route>
      <Route path="/suggested"><PageWrapper><Suggested /></PageWrapper></Route>
      <Route path="/plan-detail"><PageWrapper><PlanDetail /></PageWrapper></Route>
      <Route path="/vote"><PageWrapper><Vote /></PageWrapper></Route>
      <Route path="/confirmed"><PageWrapper><Confirmed /></PageWrapper></Route>
      <Route path="/memories"><PageWrapper><Memories /></PageWrapper></Route>
      <Route path="/photobooth"><PageWrapper><Photobooth /></PageWrapper></Route>
      <Route path="/pet"><PageWrapper><Pet /></PageWrapper></Route>
      <Route><PageWrapper><NotFound /></PageWrapper></Route>
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <Toaster />
        <AppShell>
          <AnimatePresence mode="wait">
            <Router />
          </AnimatePresence>
        </AppShell>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

import { useLocation } from "wouter";
import { motion } from "framer-motion";
import { Zap, Users, Camera, ArrowRight } from "lucide-react";

const BLUE = "#3B82F6";
const BLUE_BRIGHT = "#2563EB";
const T1 = "#0F172A";
const T2 = "#475569";
const T3 = "#94A3B8";
const SURF = "#FFFFFF";
const BORDER = "rgba(0,0,0,0.08)";
const SHADOW = "0 2px 8px rgba(0,0,0,0.10), 0 8px 24px rgba(0,0,0,0.07)";

const floatingChips = [
  { text: "3 plan sẵn sàng", icon: Zap, top: "1rem", left: "1rem", delay: 0 },
  { text: "4 bạn đang vote", icon: Users, top: "3.2rem", right: "1rem", delay: 0.22 },
  { text: "Đã lưu kỷ niệm", icon: Camera, bottom: "3.8rem", left: "1.8rem", delay: 0.44 },
];

export default function Onboarding() {
  const [, setLocation] = useLocation();

  return (
    <div className="flex-1 flex flex-col px-6 py-4 overflow-hidden relative" style={{ background: "#F7F5F0" }}>
      {/* Status bar */}
      <div className="flex items-center justify-between mb-4">
        <span className="text-sm font-semibold" style={{ color: T2 }}>9:41</span>
        <div className="flex items-center gap-1">
          {[0, 1, 2].map(i => (
            <div key={i} style={{ width: i < 2 ? 4 : 16, height: i < 2 ? 4 : 8, background: T1, borderRadius: i === 2 ? 2 : "50%", opacity: i < 2 ? 0.3 : 1 }} />
