@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — UNICORN EDITION v2
   Soul, texture, delight. Not just clean.
   ============================================================ */

html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #F7F5F0;
  color: #0F172A;
}

:root {
  --bg: #F7F5F0;
  --bg-warm: #F2EEE7;
  --surface: #FFFFFF;
  --surface-warm: #FEFCF8;
  --surface-elevated: #F5F0E8;
  --border-subtle: rgba(0, 0, 0, 0.07);
  --border-medium: rgba(0, 0, 0, 0.13);

  --text-primary: #0F172A;
  --text-secondary: #475569;
  --text-muted: #94A3B8;

  --blue: #3B82F6;
  --blue-bright: #2563EB;
  --blue-dim: rgba(59, 130, 246, 0.10);

  --amber: #F59E0B;
  --green: #22C55E;
  --coral: #F97316;

  /* shadcn */
  --background: 37 25% 96%;
  --foreground: 222 47% 7%;
  --muted: 37 15% 92%;
  --muted-foreground: 215 16% 47%;
  --popover: 0 0% 100%;
  --popover-foreground: 222 47% 7%;
  --border: 37 15% 88%;
  --input: 37 15% 88%;
  --card: 0 0% 100%;
  --card-foreground: 222 47% 7%;
  --primary: 217 91% 60%;
  --primary-foreground: 0 0% 100%;
  --secondary: 37 15% 92%;
  --secondary-foreground: 222 47% 7%;
  --accent: 217 91% 60%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;
  --ring: 217 91% 60%;
  --radius: 0.75rem;

  --shadow-card: 0 1px 3px rgba(0,0,0,0.05), 0 4px 16px rgba(0,0,0,0.05);
  --shadow-card-hover: 0 4px 8px rgba(0,0,0,0.07), 0 12px 32px rgba(0,0,0,0.09);
  --shadow-float: 0 8px 32px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.06);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@layer base {
  * { @apply border-border; }
  body { background: var(--bg); color: var(--text-primary); }
}

@layer components {
  .card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 18px;
    box-shadow: var(--shadow-card);
    transition: box-shadow 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }
  .card:hover { box-shadow: var(--shadow-card-hover); }

  .card-warm {
    background: var(--surface-warm);
    border: 1px solid rgba(0,0,0,0.06);
    border-radius: 18px;
    box-shadow: var(--shadow-card);
  }

  .card-float {
    background: var(--surface);
    border: 1px solid rgba(255,255,255,0.60);
    border-radius: 20px;
    box-shadow: var(--shadow-float);
  }

  /* Legacy compat */
  .obsidian-card { @apply card; }
  .obsidian-card-elevated { @apply card-warm; }

  /* Bottom dock */
  .premium-bottom-dock {
    position: fixed; bottom: 0; left: 0; right: 0; z-index: 50;
    background: rgba(255,255,255,0.92);
    backdrop-filter: blur(28px) saturate(180%);
    -webkit-backdrop-filter: blur(28px) saturate(180%);
    border-top: 1px solid rgba(0,0,0,0.07);
    box-shadow: 0 -1px 0 rgba(0,0,0,0.06), 0 -8px 24px rgba(0,0,0,0.05);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  /* Primary CTAs */
  .premium-cta {
    background: #0F172A; color: #FFFFFF; border: none; border-radius: 14px;
    font-weight: 700; font-size: 16px;
    box-shadow: 0 2px 8px rgba(15,23,42,0.25);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta:hover { background: #1E293B; transform: translateY(-1px); box-shadow: 0 4px 16px rgba(15,23,42,0.30); }
  .premium-cta:active { transform: scale(0.98); }

  .premium-cta-mint {
    background: var(--blue); color: #FFFFFF; border: none; border-radius: 14px;
    font-weight: 700; font-size: 16px;
    box-shadow: 0 2px 12px rgba(59,130,246,0.35);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta-mint:hover { background: var(--blue-bright); transform: translateY(-1px); box-shadow: 0 4px 20px rgba(59,130,246,0.42); }
  .premium-cta-mint:active { transform: scale(0.98); }

  .premium-cta-ghost {
    background: rgba(255,255,255,0.12); color: rgba(255,255,255,0.90);
    border: 1px solid rgba(255,255,255,0.20); border-radius: 14px;
    font-weight: 600; font-size: 15px; backdrop-filter: blur(12px);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta-ghost:hover { background: rgba(255,255,255,0.20); }
  .premium-cta-ghost:active { transform: scale(0.98); }

  .status-pill {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 3px 9px; border-radius: 100px;
    font-size: 11px; font-weight: 600; letter-spacing: 0.02em;
  }
  .status-pill.mint { background: rgba(59,130,246,0.10); color: #2563EB; border: 1px solid rgba(59,130,246,0.20); }
  .status-pill.warning { background: rgba(245,158,11,0.10); color: #92400E; border: 1px solid rgba(245,158,11,0.22); }
  .status-pill.muted { background: #F1F5F9; color: var(--text-muted); border: 1px solid var(--border-subtle); }
  .status-pill.green { background: rgba(34,197,94,0.10); color: #15803D; border: 1px solid rgba(34,197,94,0.22); }

  .page-label {
    font-size: 10px; font-weight: 700;
    text-transform: uppercase; letter-spacing: 0.22em;
    color: var(--text-muted);
  }

  .match-glow-card {
    border: 2px solid rgba(59,130,246,0.40) !important;
    box-shadow: 0 0 0 4px rgba(59,130,246,0.08), 0 8px 32px rgba(59,130,246,0.18) !important;
  }

  .urgency-banner {
    background: linear-gradient(135deg, #0F172A 0%, #1E3A8A 100%);
    border-radius: 16px;
    box-shadow: 0 4px 20px rgba(15,23,42,0.20);
  }

  .ai-hint {
    background: linear-gradient(135deg, rgba(59,130,246,0.08), rgba(139,92,246,0.08));
    border: 1px solid rgba(59,130,246,0.16);
    border-radius: 12px; padding: 10px 14px;
  }

  /* Aurora blob base */
  .aurora-blob {
    position: absolute; border-radius: 50%;
    filter: blur(80px); pointer-events: none;
    will-change: transform;
  }

  .grain-overlay {
    position: fixed; inset: 0;
    pointer-events: none; z-index: 999;
    opacity: 0.018;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat; background-size: 128px 128px;
  }
}

/* ======================================
   KEYFRAMES
   ====================================== */

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

@keyframes confetti-fall {
  0%   { transform: translateY(-10px) rotate(var(--rot, 0deg)) scale(1); opacity: 1; }
  80%  { opacity: 1; }
  100% { transform: translateY(110vh) rotate(calc(var(--rot, 0deg) + 540deg)) scale(0.6); opacity: 0; }
}

.confetti-piece {
  position: absolute;
  animation: confetti-fall var(--duration, 3s) var(--delay, 0s) ease-in forwards;
}

/* Aurora animated blobs */
@keyframes aurora-1 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  30%  { transform: translate(40px, -35px) scale(1.12); }
  65%  { transform: translate(-25px, 22px) scale(0.91); }
}
@keyframes aurora-2 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  40%  { transform: translate(-55px, 32px) scale(1.18); }
  72%  { transform: translate(32px, -18px) scale(0.88); }
}
@keyframes aurora-3 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  55%  { transform: translate(22px, 45px) scale(1.10); }
}

/* Stars in dark backgrounds */
@keyframes star-twinkle {
  0%, 100% { opacity: 0.15; transform: scale(0.8); }
  50% { opacity: 0.9; transform: scale(1.6); }
}

/* Overshoot pop for buttons */
@keyframes overshoot-pop {
  0%   { transform: scale(1); }
  25%  { transform: scale(0.86); }
  65%  { transform: scale(1.13); }
  100% { transform: scale(1); }
}

/* Slide up */
@keyframes slide-up-fade {
  0% { opacity: 0; transform: translateY(14px); }
  100% { opacity: 1; transform: translateY(0); }
}
@keyframes activity-in {
  0% { opacity: 0; transform: translateY(-8px) scale(0.96); }
  100% { opacity: 1; transform: translateY(0) scale(1); }
}

/* Level-up flash */
@keyframes level-flash {
  0% { opacity: 0; }
  10% { opacity: 1; }
  90% { opacity: 1; }
  100% { opacity: 0; }
}

/* Pulse glow */
@keyframes glow-pulse {
  0%, 100% { opacity: 0.35; transform: scale(1); }
  50% { opacity: 0.65; transform: scale(1.15); }
}

/* Star field drift */
@keyframes star-drift {
  0% { transform: translateY(0px); opacity: 0; }
  8% { opacity: 1; }
  92% { opacity: 0.7; }
  100% { transform: translateY(-120px); opacity: 0; }
}

import { useState } from "react";
import { useLocation } from "wouter";
import { motion, AnimatePresence } from "framer-motion";
import { Zap, Users, Camera, ArrowRight } from "lucide-react";

const BLUE = "#3B82F6";
const T1 = "#0F172A";
const T2 = "#475569";
const T3 = "#94A3B8";
const SURF = "#FFFFFF";
const SHADOW = "0 2px 8px rgba(0,0,0,0.10), 0 8px 24px rgba(0,0,0,0.07)";

// Word-by-word headline
const headlineWords = [
  { text: "Plan", blue: false, br: false },
  { text: "đi chơi", blue: false, br: true },
  { text: "cùng nhau,", blue: false, br: false },
  { text: "dễ hơn", blue: true, br: true },
  { text: "bao giờ hết", blue: true, br: false },
];

const floatingChips = [
  { text: "3 plan sẵn sàng", icon: Zap, top: "1rem", left: "1rem", delay: 0.6 },
  { text: "4 bạn đang vote", icon: Users, top: "3.4rem", right: "1rem", delay: 0.8 },
  { text: "Đã lưu kỷ niệm", icon: Camera, bottom: "4rem", left: "2rem", delay: 1.0 },
];

// Spark burst on CTA
function SparkBurst({ visible, key: k }: { visible: boolean; key: number }) {
  if (!visible) return null;
  return (
    <>
      {Array.from({ length: 10 }, (_, i) => {
        const angle = (i * 36) * Math.PI / 180;
        return (
          <motion.div key={`spark-${k}-${i}`}
            className="absolute pointer-events-none rounded-full"
            style={{
              width: i % 2 === 0 ? 6 : 4,
              height: i % 2 === 0 ? 6 : 4,
              background: [BLUE, "#8B5CF6", "#F59E0B", "#22C55E"][i % 4],
              top: "50%", left: "50%",
            }}
            initial={{ x: 0, y: 0, scale: 0, opacity: 1 }}
            animate={{
              x: Math.cos(angle) * (50 + i * 5),
              y: Math.sin(angle) * (50 + i * 5),
              scale: [0, 1.6, 0],
              opacity: [1, 1, 0],
            }}
            transition={{ duration: 0.55, ease: "easeOut" }}
          />
        );
      })}
    </>
  );
}

export default function Onboarding() {
  const [, setLocation] = useLocation();
  const [sparkVisible, setSparkVisible] = useState(false);
  const [sparkKey, setSparkKey] = useState(0);

  const handleCTA = () => {
    setSparkVisible(true);
    setSparkKey(k => k + 1);
    setTimeout(() => {
      setSparkVisible(false);
      setLocation("/home");
    }, 500);
  };

  return (
    <div className="flex-1 flex flex-col px-6 py-4 overflow-hidden relative" style={{ background: "#F7F5F0" }}>

      {/* Aurora background blobs — 3 animated blobs */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden" style={{ zIndex: 0 }}>
        {/* Blue aurora */}
        <div className="aurora-blob"
          style={{
            width: 340, height: 340,
            top: -60, right: -80,
            background: "radial-gradient(circle, rgba(59,130,246,0.22) 0%, rgba(139,92,246,0.12) 50%, transparent 70%)",
            animation: "aurora-1 12s ease-in-out infinite",
          }} />
        {/* Amber aurora */}
        <div className="aurora-blob"
          style={{
            width: 280, height: 280,
            bottom: 80, left: -60,
            background: "radial-gradient(circle, rgba(245,158,11,0.16) 0%, rgba(249,115,22,0.08) 50%, transparent 70%)",
            animation: "aurora-2 15s ease-in-out infinite",
          }} />
        {/* Purple aurora */}
        <div className="aurora-blob"
          style={{
            width: 200, height: 200,
            top: "40%", left: "30%",
            background: "radial-gradient(circle, rgba(139,92,246,0.12) 0%, transparent 70%)",
            animation: "aurora-3 18s ease-in-out infinite",
          }} />
      </div>

      {/* Content */}
      <div className="relative z-10 flex flex-col flex-1">
        {/* Status bar */}
        <div className="flex items-center justify-between mb-4">
          <span className="text-sm font-semibold" style={{ color: T2 }}>9:41</span>
          <div className="flex items-center gap-1">
            {[0, 1, 2].map(i => (
              <div key={i} style={{ width: i < 2 ? 4 : 16, height: i < 2 ? 4 : 8, background: T1, borderRadius: i === 2 ? 2 : "50%", opacity: i < 2 ? 0.3 : 1 }} />
            ))}
          </div>
        </div>

        {/* Brand */}
        <div className="mb-4"><div className="page-label">GatherGo</div></div>

        {/* Hero image */}
        <motion.div
          initial={{ opacity: 0, y: 24, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          transition={{ duration: 0.65, ease: [0.25, 0.46, 0.45, 0.94] }}
          className="relative w-full h-[272px] rounded-[24px] overflow-hidden mb-6"
          style={{ boxShadow: "0 12px 48px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.10)" }}>
          <img
            src="https://images.unsplash.com/photo-1528605248644-14dd04022da1?w=700&auto=format&fit=crop"
            alt="Friends gathering" className="w-full h-full object-cover" />
          <div className="absolute inset-0"
            style={{ background: "linear-gradient(175deg, rgba(15,23,42,0.04) 0%, rgba(15,23,42,0.35) 50%, rgba(15,23,42,0.72) 100%)" }} />

          {/* Floating chips */}
          {floatingChips.map(({ text, icon: Icon, top, left, right, bottom, delay }: any, i) => (
            <motion.div key={i}
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1, y: [0, -(3 + i * 1.5), 0] }}
              transition={{ opacity: { delay, duration: 0.4 }, scale: { delay, duration: 0.4 }, y: { duration: 3 + i * 0.5, repeat: Infinity, ease: "easeInOut", delay: delay + 0.4 } }}
              className="absolute flex items-center gap-2 px-3 py-2 rounded-2xl"
              style={{ top, left, right, bottom, background: "rgba(255,255,255,0.94)", backdropFilter: "blur(20px)", border: "1px solid rgba(255,255,255,0.60)", boxShadow: SHADOW }}>
              <div className="w-6 h-6 rounded-lg flex items-center justify-center flex-shrink-0"
