        <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.9 }}
          className="text-[15px] leading-relaxed mb-5" style={{ color: T2 }}>
          Chọn mood, thời gian và ngân sách. GatherGo tạo plan địa phương để cả nhóm dễ đồng ý.
        </motion.p>

        {/* Feature rows */}
        <div className="flex flex-col gap-2.5 mb-7">
          {[
            { icon: Zap, label: "Gợi ý nhanh theo mood & vibe nhóm", color: BLUE, delay: 1.0 },
            { icon: Users, label: "Vote cùng nhóm, không cần chat lòng vòng", color: "#8B5CF6", delay: 1.1 },
            { icon: Camera, label: "Lưu kỷ niệm mỗi chuyến đi lại", color: "#F59E0B", delay: 1.2 },
          ].map(({ icon: Icon, label, color, delay }) => (
            <motion.div key={label} initial={{ opacity: 0, x: -12 }} animate={{ opacity: 1, x: 0 }}
              transition={{ delay, type: "spring", stiffness: 400, damping: 28 }}
              className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0"
                style={{ background: `${color}15`, border: `1px solid ${color}25` }}>
                <Icon className="w-4 h-4" style={{ color }} />
              </div>
              <span className="text-[13px] font-medium" style={{ color: T2 }}>{label}</span>
            </motion.div>
          ))}
        </div>

        {/* CTA with spark burst */}
        <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 1.3 }}
          className="relative">
          <motion.button
            whileHover={{ scale: 1.01, y: -1 }}
            whileTap={{ scale: 0.97 }}
            onClick={handleCTA}
            className="w-full h-[58px] premium-cta-mint flex items-center justify-center gap-2 text-[16px] relative overflow-visible">
            Bắt đầu tạo Gather
            <ArrowRight className="w-4 h-4" />
            <AnimatePresence>
              {sparkVisible && <SparkBurst visible={sparkVisible} key={sparkKey} />}
            </AnimatePresence>
          </motion.button>
        </motion.div>

        <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.4 }}
          className="text-center text-[12px] mt-3" style={{ color: T3 }}>
          Không feed công khai · Không chat lòng vòng · Riêng tư 100%
        </motion.p>

        <div className="flex justify-center mt-auto mb-2 pt-4">
          <div className="w-[120px] h-1 rounded-full" style={{ background: "rgba(15,23,42,0.12)" }} />
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { PawPrint, Heart, Zap, Star, Trophy, MapPin, Camera, Lock, Crown, Sparkles } from "lucide-react";
import BottomNav from "@/components/BottomNav";

const BLUE = "#3B82F6";
const BLUE_BRIGHT = "#2563EB";
const T1 = "#0F172A";
const T2 = "#475569";
const T3 = "#94A3B8";
const BORDER = "rgba(0,0,0,0.07)";
const SHADOW = "0 1px 3px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.06)";
const SURF = "#FFFFFF";
const SURF2 = "#F0F5FF";

// Warm Mimi colors
const MIMI_BODY = "#FFD4A8";
const MIMI_STROKE = "#FDBA74";
const MIMI_EAR_INNER = "#FFB085";
const MIMI_NOSE = "#FB923C";
const MIMI_CHEEK = "#FCA5A5";
const MIMI_EYE = "#1A0800";
const MIMI_WHISKER = "#FDBA74";

function getEnergyState(energy: number) {
  if (energy >= 85) return { label: "Đang rất vui 😄", color: "#22C55E", desc: "Mimi tràn đầy năng lượng!" };
  if (energy >= 65) return { label: "Ổn áp 😊", color: BLUE, desc: "Mimi đang trong trạng thái tốt." };
  if (energy >= 40) return { label: "Hơi đói rồi 😐", color: "#F59E0B", desc: "Thêm vài kỷ niệm nữa là Mimi vui ngay." };
  return { label: "Đói bụng rồi 🥺", color: "#EF4444", desc: "Mimi cần được cho ăn kỷ niệm!" };
}

// Stars for dark stage background
function StageStars() {
  const stars = useMemo(() => Array.from({ length: 28 }, (_, i) => ({
    id: i,
    left: Math.random() * 100,
    top: Math.random() * 100,
    size: 0.8 + Math.random() * 1.4,
    duration: 2 + Math.random() * 4,
    delay: Math.random() * 4,
    opacity: 0.2 + Math.random() * 0.5,
  })), []);

  return (
    <>
      {stars.map(s => (
        <div key={s.id} style={{
          position: "absolute",
          left: `${s.left}%`, top: `${s.top}%`,
          width: s.size, height: s.size,
          borderRadius: "50%",
          background: "white",
          animation: `star-twinkle ${s.duration}s ${s.delay}s ease-in-out infinite`,
          pointerEvents: "none",
        }} />
      ))}
    </>
  );
}

// Animated Mimi SVG — warm, expressive, eye-follow
function MimiSVG({ eyeOffset, isHappy, size = 120 }: { eyeOffset: { x: number; y: number }; isHappy: boolean; size?: number }) {
  const ex = eyeOffset.x;
  const ey = eyeOffset.y;
  return (
    <svg viewBox="0 0 120 120" width={size} height={size}>
      {/* Body */}
      <ellipse cx="60" cy="82" rx="33" ry="26" fill={MIMI_BODY} stroke={MIMI_STROKE} strokeWidth="2.5" />
