              width: 200, height: 200,
              background: "radial-gradient(circle, rgba(59,130,246,0.22) 0%, rgba(139,92,246,0.08) 50%, transparent 70%)",
              filter: "blur(30px)",
            }} />

          {/* Second warm glow */}
          <motion.div
