              }
              className="relative"
            >
              <MimiSVG eyeOffset={eyeOffset} isHappy={isHappy} size={130} />

              {/* Tap burst particles */}
              <AnimatePresence>
                {isHappy && [...Array(14)].map((_, i) => {
                  const angle = (i * (360 / 14)) * Math.PI / 180;
                  return (
                    <motion.div key={`spark-${sparkId}-${i}`}
