  const [showRing, setShowRing] = useState(false);
  const [justTapped, setJustTapped] = useState<string | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setShowActivity(true), 600);
    return () => clearTimeout(t);
  }, []);

  const handleVote = (choice: string) => {
