@tailwind base;
@tailwind components;
@tailwind utilities;

/* ============================================================
   GATHERGO — WARM INK EDITION
   Vietnamese lacquer red · papyrus · editorial warmth
   Not blue-500. Not safe. Not AI-gen.
   ============================================================ */

html, body {
  overflow-x: hidden;
  max-width: 100vw;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif;
  font-feature-settings: "rlig" 1, "calt" 1, "tnum" 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: #EEE6D4;
  color: #1A0E07;
}

:root {
  /* ── WARM INK palette ──────────────────────────────────── */
  --bg: #EEE6D4;
  --bg-warm: #E8D8BC;
  --surface: #F9F4EA;
  --surface-warm: #F4EDD8;
  --surface-tinted: #E8D8BC;
  --surface-dark: #1A0E07;
  --border-subtle: rgba(26, 14, 7, 0.10);
  --border-medium: rgba(26, 14, 7, 0.18);

  --text-primary: #1A0E07;
  --text-secondary: #5C4033;
  --text-muted: #9C8470;

  /* Primary — Vietnamese lacquer red (đỏ sơn mài) */
  --primary-color: #C8371E;
  --primary-bright: #A62D17;
  --primary-dim: rgba(200, 55, 30, 0.10);

  /* Kept as aliases for legacy code */
  --blue: #C8371E;
  --blue-bright: #A62D17;
  --blue-dim: rgba(200, 55, 30, 0.10);

  --amber: #C8860A;
  --green: #3D6B4F;
  --coral: #E05A2B;

  /* ── shadcn tokens (warm ink) ──────────────────────────── */
  --background: 40 33% 88%;
  --foreground: 24 58% 6%;
  --muted: 38 25% 82%;
  --muted-foreground: 24 18% 40%;
  --popover: 42 67% 95%;
  --popover-foreground: 24 58% 6%;
  --border: 38 18% 78%;
  --input: 38 18% 78%;
  --card: 42 67% 95%;
  --card-foreground: 24 58% 6%;
  --primary: 10 74% 45%;
  --primary-foreground: 0 0% 100%;
  --secondary: 38 25% 82%;
  --secondary-foreground: 24 58% 6%;
  --accent: 10 74% 45%;
  --accent-foreground: 0 0% 100%;
  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;
  --ring: 10 74% 45%;
  --radius: 0.625rem;

  /* ── shadows — warm tinted ─────────────────────────────── */
  --shadow-card: 0 1px 3px rgba(26,14,7,0.06), 0 4px 16px rgba(26,14,7,0.06);
  --shadow-card-hover: 0 4px 8px rgba(26,14,7,0.10), 0 12px 32px rgba(26,14,7,0.12);
  --shadow-float: 0 8px 32px rgba(26,14,7,0.14), 0 2px 8px rgba(26,14,7,0.08);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@layer base {
  * { @apply border-border; }
  body { background: var(--bg); color: var(--text-primary); }
}

@layer components {

  /* ── Cards — 14px radius, warm border ──────────────────── */
  .card {
    background: var(--surface);
    border: 1px solid var(--border-subtle);
    border-radius: 14px;
    box-shadow: var(--shadow-card);
    transition: box-shadow 0.2s var(--ease-smooth), transform 0.2s var(--ease-smooth);
  }
  .card:hover { box-shadow: var(--shadow-card-hover); }

  .card-warm {
    background: var(--surface-warm);
    border: 1px solid rgba(26,14,7,0.08);
    border-radius: 14px;
    box-shadow: var(--shadow-card);
  }

  .card-tinted {
    background: var(--surface-tinted);
    border: 1px solid rgba(26,14,7,0.10);
    border-radius: 14px;
    box-shadow: var(--shadow-card);
  }

  .card-dark {
    background: var(--surface-dark);
    border: 1px solid rgba(255,255,255,0.06);
    border-radius: 14px;
    box-shadow: 0 4px 24px rgba(26,14,7,0.28);
  }

  .card-float {
    background: var(--surface);
    border: 1px solid rgba(255,255,255,0.60);
    border-radius: 16px;
    box-shadow: var(--shadow-float);
  }

  .surface-tinted { background: var(--surface-tinted); }
  .surface-dark { background: var(--surface-dark); }

  /* Legacy compat */
  .obsidian-card { @apply card; }
  .obsidian-card-elevated { @apply card-warm; }

  /* ── Bottom dock ────────────────────────────────────────── */
  .premium-bottom-dock {
    position: fixed; bottom: 0; left: 0; right: 0; z-index: 50;
    background: rgba(249,244,234,0.94);
    backdrop-filter: blur(28px) saturate(160%);
    -webkit-backdrop-filter: blur(28px) saturate(160%);
    border-top: 1px solid rgba(26,14,7,0.08);
    box-shadow: 0 -1px 0 rgba(26,14,7,0.06), 0 -8px 24px rgba(26,14,7,0.04);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  /* ── CTAs ───────────────────────────────────────────────── */
  .premium-cta {
    background: var(--surface-dark); color: #FFFFFF; border: none; border-radius: 14px;
    font-weight: 700; font-size: 16px;
    box-shadow: 0 2px 8px rgba(26,14,7,0.30);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta:hover { background: #2E1A0F; transform: translateY(-1px); box-shadow: 0 4px 16px rgba(26,14,7,0.36); }
  .premium-cta:active { transform: scale(0.98); }

  .premium-cta-mint {
    background: var(--primary-color); color: #FFFFFF; border: none; border-radius: 14px;
    font-weight: 700; font-size: 16px;
    box-shadow: 0 2px 12px rgba(200,55,30,0.38);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta-mint:hover { background: var(--primary-bright); transform: translateY(-1px); box-shadow: 0 4px 20px rgba(200,55,30,0.46); }
  .premium-cta-mint:active { transform: scale(0.98); }

  .premium-cta-ghost {
    background: rgba(255,255,255,0.12); color: rgba(255,255,255,0.90);
    border: 1px solid rgba(255,255,255,0.20); border-radius: 14px;
    font-weight: 600; font-size: 15px; backdrop-filter: blur(12px);
    transition: all 0.2s var(--ease-smooth); cursor: pointer;
  }
  .premium-cta-ghost:hover { background: rgba(255,255,255,0.20); }
  .premium-cta-ghost:active { transform: scale(0.98); }

  /* ── Status pills ───────────────────────────────────────── */
  .status-pill {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 3px 9px; border-radius: 100px;
    font-size: 11px; font-weight: 600; letter-spacing: 0.02em;
  }
  .status-pill.mint { background: rgba(200,55,30,0.10); color: #A62D17; border: 1px solid rgba(200,55,30,0.22); }
  .status-pill.warning { background: rgba(200,134,10,0.10); color: #8A5C07; border: 1px solid rgba(200,134,10,0.22); }
  .status-pill.muted { background: rgba(26,14,7,0.06); color: var(--text-muted); border: 1px solid var(--border-subtle); }
  .status-pill.green { background: rgba(61,107,79,0.10); color: #2A5439; border: 1px solid rgba(61,107,79,0.22); }

  /* ── Section eyebrow — NOT uppercase, NOT all-caps ──────── */
  /* The old .page-label was the #1 AI-gen tell. This is the fix. */
  .page-label {
    font-size: 11px; font-weight: 600;
    letter-spacing: 0.04em;
    color: var(--text-muted);
  }

  /* ── Urgency banner — dark surface with warm red accent ─── */
  .urgency-banner {
    background: var(--surface-dark);
    border-radius: 14px;
    box-shadow: 0 4px 20px rgba(26,14,7,0.22);
  }

  .match-glow-card {
    border: 2px solid rgba(200,55,30,0.40) !important;
    box-shadow: 0 0 0 4px rgba(200,55,30,0.08), 0 8px 32px rgba(200,55,30,0.18) !important;
  }

  .ai-hint {
    background: linear-gradient(135deg, rgba(200,55,30,0.06), rgba(200,134,10,0.06));
    border: 1px solid rgba(200,55,30,0.14);
    border-radius: 12px; padding: 10px 14px;
  }

  /* ── Aurora blob base ───────────────────────────────────── */
  .aurora-blob {
    position: absolute; border-radius: 50%;
    filter: blur(80px); pointer-events: none;
    will-change: transform;
  }

  /* ── Grain overlay — subtle paper texture ───────────────── */
  .grain-overlay {
    position: fixed; inset: 0;
    pointer-events: none; z-index: 999;
    opacity: 0.025;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
    background-repeat: repeat; background-size: 128px 128px;
  }
}

/* ======================================
   KEYFRAMES
   ====================================== */

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-8px); }
}

@keyframes fade-up {
  0% { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: none; }
}

@keyframes confetti-fall {
  0%   { transform: translateY(-10px) rotate(var(--rot, 0deg)) scale(1); opacity: 1; }
  80%  { opacity: 1; }
  100% { transform: translateY(110vh) rotate(calc(var(--rot, 0deg) + 540deg)) scale(0.6); opacity: 0; }
}

.confetti-piece {
  position: absolute;
  animation: confetti-fall var(--duration, 3s) var(--delay, 0s) ease-in forwards;
}

/* Aurora animated blobs */
@keyframes aurora-1 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  30%  { transform: translate(40px, -35px) scale(1.12); }
  65%  { transform: translate(-25px, 22px) scale(0.91); }
}
@keyframes aurora-2 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  40%  { transform: translate(-55px, 32px) scale(1.18); }
  72%  { transform: translate(32px, -18px) scale(0.88); }
}
@keyframes aurora-3 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  55%  { transform: translate(22px, 45px) scale(1.10); }
}

/* Stars in dark backgrounds */
@keyframes star-twinkle {
  0%, 100% { opacity: 0.15; transform: scale(0.8); }
  50% { opacity: 0.9; transform: scale(1.6); }
}

/* Overshoot pop for buttons */
@keyframes overshoot-pop {
  0%   { transform: scale(1); }
  25%  { transform: scale(0.86); }
  65%  { transform: scale(1.13); }
  100% { transform: scale(1); }
}

/* Slide up */
@keyframes slide-up-fade {
  0% { opacity: 0; transform: translateY(14px); }
  100% { opacity: 1; transform: translateY(0); }
}
@keyframes activity-in {
  0% { opacity: 0; transform: translateY(-8px) scale(0.96); }
  100% { opacity: 1; transform: translateY(0) scale(1); }
}

/* Level-up flash */
@keyframes level-flash {
  0% { opacity: 0; }
  10% { opacity: 1; }
  90% { opacity: 1; }
  100% { opacity: 0; }
}

/* Pulse glow */
@keyframes glow-pulse {
  0%, 100% { opacity: 0.35; transform: scale(1); }
  50% { opacity: 0.65; transform: scale(1.15); }
}

/* Star field drift */
@keyframes star-drift {
  0% { transform: translateY(0px); opacity: 0; }
  8% { opacity: 1; }
  92% { opacity: 0.7; }
  100% { transform: translateY(-120px); opacity: 0; }
}

